// ChatMessageModal.jsx - With selectedUser as prop
import React, { useState, useEffect, useRef } from "react";
import { X, Send } from "lucide-react";
import {
    getMessages,
    sendMessage,
} from "../../../api/chatApi";
import axios from "axios";
import { API_BASE_URL } from "../../../config/config";

export default function ChatMessageModal({ onClose, currentUser, selectedUser }) {
    const [messages, setMessages] = useState([]);
    const [messageInput, setMessageInput] = useState("");
    const [conversation, setConversation] = useState(null);
    const [loading, setLoading] = useState(false);
    const messagesEndRef = useRef(null);
    const API_URL = `${API_BASE_URL}api/user/chatmessage`;

    // Get or create conversation when component mounts
    useEffect(() => {
        if (currentUser?.id && selectedUser?.id) {
            getOrCreateConversation();
        }
    }, [selectedUser?.id]);

    const getOrCreateConversation = async () => {
        setLoading(true);
        try {
            console.log("🔍 API_URL:", API_URL);
            console.log("🔍 Request Data:", {
                participant1_type: currentUser?.type,
                participant1_id: currentUser?.id,
                participant2_type: selectedUser?.type,
                participant2_id: selectedUser?.id
            });

            const response = await axios.post(`${API_URL}/get_or_create_conversation`,
                {
                    participant1_type: currentUser?.type,
                    participant1_id: currentUser?.id,
                    participant2_type: selectedUser?.type,
                    participant2_id: selectedUser?.id
                },
                {
                    headers: {
                        Accept: "application/json",
                        "Content-Type": "application/json",
                    },

                }
            );

            console.log("✅ Response:", response.data);

            if (response.data.success) {
                setConversation(response.data.conversation);
                loadMessages(response.data.conversation.conversation_id);
            }
        } catch (error) {
            console.error("❌ Error Details:");
            console.error("   Message:", error.message);
            console.error("   Code:", error.code);
            console.error("   Config URL:", error.config?.url);

            if (error.response) {
                console.error("   Response Status:", error.response.status);
                console.error("   Response Data:", error.response.data);
            } else if (error.request) {
                console.error("   No response received. Backend may not be running.");
            }
        } finally {
            setLoading(false);
        }
    };
    const loadMessages = async (conversationId) => {
        const response = await getMessages(conversationId, currentUser.id, currentUser.type);
        if (response.success) {
            setMessages(response.messages);
            scrollToBottom();
        }
    };

    const handleSendMessage = async () => {
        if (!messageInput.trim() || !conversation) return;

        const newMsg = {
            id: Date.now(),
            message: messageInput,
            isMe: true,
            created_at: new Date(),
            sender_name: currentUser.name
        };

        setMessages(prev => [...prev, newMsg]);
        setMessageInput("");
        scrollToBottom();

        await sendMessage(
            conversation.conversation_id,
            currentUser.type, currentUser.id,
            selectedUser.type, selectedUser.id,
            messageInput
        );
    };

    const handleKeyPress = (e) => {
        if (e.key === "Enter" && !e.shiftKey) {
            e.preventDefault();
            handleSendMessage();
        }
    };

    const scrollToBottom = () => {
        setTimeout(() => {
            messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
        }, 100);
    };

    const getRoleColor = (role) => {
        if (role === "company") return "#f44336";
        if (role === "investor") return "#4caf50";
        if (role === "admin") return "#9c27b0";
        return "#6c757d";
    };

    return (
        <div style={styles.modalOverlay}>
            <div style={styles.modalContainer}>
                {/* Header */}
                <div style={styles.header}>
                    <div style={styles.headerLeft}>
                        <div style={styles.avatarPlaceholder}>
                            {selectedUser?.name?.charAt(0) || "U"}
                        </div>
                        <div>
                            <h5 style={styles.headerName}>{selectedUser?.name}</h5>
                            <span style={{
                                ...styles.roleBadge,
                                backgroundColor: getRoleColor(selectedUser?.type)
                            }}>
                                {selectedUser?.role || selectedUser?.type}
                            </span>
                        </div>
                    </div>
                    <button onClick={onClose} style={styles.closeBtn}>
                        <X size={20} />
                    </button>
                </div>

                {/* Messages Area */}
                <div style={styles.messagesArea}>
                    {loading ? (
                        <div style={styles.loading}>Loading messages...</div>
                    ) : messages.length === 0 ? (
                        <div style={styles.noMessagesYet}>
                            <p>No messages yet</p>
                            <p style={styles.noMessagesSubtext}>Send a message to start the conversation</p>
                        </div>
                    ) : (
                        messages.map((msg, idx) => (
                            <div
                                key={msg.id || idx}
                                style={{
                                    ...styles.messageRow,
                                    justifyContent: msg.sender_id === currentUser?.id ? "flex-end" : "flex-start"
                                }}
                            >
                                <div style={{
                                    ...styles.messageBubble,
                                    backgroundColor: msg.sender_id === currentUser?.id ? "#ff3e43" : "#f1f3f4",
                                    color: msg.sender_id === currentUser?.id ? "#fff" : "#202124"
                                }}>
                                    <p style={styles.messageText}>{msg.message}</p>
                                    <span style={styles.messageTime}>
                                        {new Date(msg.created_at).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                                    </span>
                                </div>
                            </div>
                        ))
                    )}
                    <div ref={messagesEndRef} />
                </div>

                {/* Input Area */}
                <div style={styles.inputArea}>
                    <input
                        type="text"
                        placeholder={`Message ${selectedUser?.name}...`}
                        value={messageInput}
                        onChange={(e) => setMessageInput(e.target.value)}
                        onKeyPress={handleKeyPress}
                        style={styles.input}
                    />
                    <button
                        onClick={handleSendMessage}
                        style={styles.sendBtn}
                        disabled={!messageInput.trim()}
                    >
                        <Send size={18} color="#fff" />
                    </button>
                </div>
            </div>
        </div>
    );
}

const styles = {
    modalOverlay: {
        position: "fixed",
        top: 0, left: 0, right: 0, bottom: 0,
        backgroundColor: "rgba(0,0,0,0.7)",
        zIndex: 99999,
        display: "flex",
        alignItems: "center",
        justifyContent: "center",
        backdropFilter: "blur(8px)"
    },
    modalContainer: {
        width: "90%",
        maxWidth: "500px",
        height: "70vh",
        backgroundColor: "#fff",
        borderRadius: "16px",
        display: "flex",
        flexDirection: "column",
        overflow: "hidden",
        boxShadow: "0 20px 60px rgba(0,0,0,0.3)"
    },
    header: {
        padding: "16px 20px",
        borderBottom: "1px solid #e9ecef",
        display: "flex",
        justifyContent: "space-between",
        alignItems: "center",
        backgroundColor: "#fff"
    },
    headerLeft: {
        display: "flex",
        alignItems: "center",
        gap: "12px"
    },
    avatarPlaceholder: {
        width: "40px",
        height: "40px",
        borderRadius: "50%",
        backgroundColor: "#ff3e43",
        color: "#fff",
        display: "flex",
        alignItems: "center",
        justifyContent: "center",
        fontWeight: "bold",
        fontSize: "16px"
    },
    headerName: {
        margin: 0,
        fontSize: "16px",
        fontWeight: 600
    },
    roleBadge: {
        fontSize: "10px",
        padding: "2px 8px",
        borderRadius: "4px",
        color: "#fff",
        display: "inline-block"
    },
    closeBtn: {
        background: "none",
        border: "none",
        cursor: "pointer",
        padding: "4px",
        borderRadius: "50%",
        display: "flex",
        alignItems: "center",
        justifyContent: "center"
    },
    messagesArea: {
        flex: 1,
        overflowY: "auto",
        padding: "20px",
        display: "flex",
        flexDirection: "column",
        gap: "12px",
        backgroundColor: "#f8f9fa"
    },
    loading: {
        textAlign: "center",
        padding: "40px",
        color: "#6c757d"
    },
    noMessagesYet: {
        textAlign: "center",
        padding: "40px",
        color: "#6c757d"
    },
    noMessagesSubtext: {
        fontSize: "12px",
        marginTop: "8px",
        color: "#adb5bd"
    },
    messageRow: {
        display: "flex"
    },
    messageBubble: {
        maxWidth: "70%",
        padding: "10px 14px",
        borderRadius: "12px",
        boxShadow: "0 1px 2px rgba(0,0,0,0.1)"
    },
    messageText: {
        margin: 0,
        fontSize: "14px",
        wordBreak: "break-word"
    },
    messageTime: {
        fontSize: "10px",
        color: "rgba(0,0,0,0.5)",
        display: "block",
        marginTop: "4px"
    },
    inputArea: {
        padding: "16px 20px",
        borderTop: "1px solid #e9ecef",
        display: "flex",
        gap: "12px",
        backgroundColor: "#fff"
    },
    input: {
        flex: 1,
        padding: "10px 16px",
        border: "1px solid #ddd",
        borderRadius: "24px",
        outline: "none",
        fontSize: "14px"
    },
    sendBtn: {
        backgroundColor: "#ff3e43",
        border: "none",
        borderRadius: "50%",
        width: "40px",
        height: "40px",
        display: "flex",
        alignItems: "center",
        justifyContent: "center",
        cursor: "pointer",
        transition: "background 0.2s"
    }
};